}

export function processStockOffersAndSecureLabel(
    fields,
    merchCard,
    aemFragmentMapping,
    settings,
) {
    if (settings?.secureLabel && aemFragmentMapping?.secureLabel) {
        merchCard.setAttribute('secure-label', settings.secureLabel);
    }
}

